import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  const templates = await prisma.template.findMany({
    where: { isApproved: true },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(templates);
}

import { PrismaClient } from "@prisma/client";
import { PrismaLibSql } from "@prisma/adapter-libsql";

const globalForPrisma = globalThis as unknown as { prisma: PrismaClient };

function createPrismaClient() {
  const adapter = new PrismaLibSql({
    url: process.env.DATABASE_URL!,
  });
  return new PrismaClient({ adapter });
}

export const prisma = globalForPrisma.prisma || createPrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";
export type BeadShape = "sphere" | "disc" | "star" | "heart" | "cylinder";

export interface CatalogBead {
  id: string;
  name: string;
  nameRu: string;
  shape: BeadShape;
  size: number;
  material: BeadType;
  color: string;
  secondaryColor?: string;
}

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
  catalogBeadId?: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

/** Wire format for design serialization (JSON → LZ-String → base64url). */
export interface SerializableDesign {
  v: 1;
  p: "pacifier-holder";
  b: string[]; // catalogBeadId strings
}

/**
 * Seed script for Prisma — populates the Template table with 8 pre-made designs.
 *
 * Usage: npx prisma db seed
 *
 * This script uses real catalog bead IDs to generate design codes via encodeDesign,
 * producing valid round-trippable codes that the frontend can decode and load.
 */

import "dotenv/config";
import { PrismaClient } from "@prisma/client";
import { PrismaLibSql } from "@prisma/adapter-libsql";
import { CATALOG_BEADS, getCatalogBead } from "../src/data/catalogBeads";
import { catalogBeadToBeadState } from "../src/lib/catalogUtils";
import { encodeDesign } from "../src/lib/serialization";

const adapter = new PrismaLibSql({ url: process.env.DATABASE_URL! });
const prisma = new PrismaClient({ adapter });

/**
 * Each template definition: name, and the catalog bead IDs that make up the design.
 * Using real IDs from the catalog spanning different materials for variety.
 */
const templates: { name: string; beads: string[] }[] = [
  {
    name: "Розовая классика",
    beads: [
      "cb-026", "cb-032", "cb-036", "cb-026", "cb-042", "cb-032",
      "cb-036", "cb-026", "cb-045", "cb-032", "cb-026", "cb-036",
    ],
  },
  {
    name: "Натуральное дерево",
    beads: [
      "cb-001", "cb-003", "cb-005", "cb-001", "cb-003", "cb-009",
      "cb-001", "cb-003", "cb-005", "cb-012", "cb-001", "cb-003",
    ],
  },
  {
    name: "Весенняя свежесть",
    beads: [
      "cb-028", "cb-034", "cb-027", "cb-028", "cb-053", "cb-028",
      "cb-034", "cb-043", "cb-028", "cb-034", "cb-027", "cb-028",
    ],
  },
  {
    name: "Яркий микс",
    beads: [
      "cb-076", "cb-078", "cb-077", "cb-079", "cb-080", "cb-076",
      "cb-078", "cb-077", "cb-079", "cb-080", "cb-076", "cb-078",
    ],
  },
  {
    name: "Лавандовый сон",
    beads: [
      "cb-029", "cb-041", "cb-035", "cb-029", "cb-050", "cb-029",
      "cb-041", "cb-035", "cb-029", "cb-050", "cb-029", "cb-041",
    ],
  },
  {
    name: "Тёплый уют",
    beads: [
      "cb-051", "cb-052", "cb-055", "cb-051", "cb-069", "cb-051",
      "cb-052", "cb-055", "cb-059", "cb-051", "cb-052", "cb-055",
    ],
  },
  {
    name: "Морской бриз",
    beads: [
      "cb-027", "cb-046", "cb-086", "cb-027", "cb-046", "cb-033",
      "cb-027", "cb-046", "cb-086", "cb-027", "cb-033", "cb-046",
    ],
  },
  {
    name: "Лесная сказка",
    beads: [
      "cb-002", "cb-004", "cb-010", "cb-057", "cb-002", "cb-004",
      "cb-057", "cb-011", "cb-002", "cb-004", "cb-010", "cb-057",
    ],
  },
];

async function main() {
  console.log("Seeding templates...");

  // Validate all bead IDs before inserting
  for (const tmpl of templates) {
    const invalid = tmpl.beads.filter((id) => !getCatalogBead(id));
    if (invalid.length > 0) {
      throw new Error(
        `Template "${tmpl.name}" has invalid bead IDs: ${invalid.join(", ")}`
      );
    }
  }

  // Clear existing templates for idempotent seeding
  await prisma.template.deleteMany();
  console.log("  Cleared existing templates.");

  for (const tmpl of templates) {
    // Convert catalog IDs → BeadState[] → design code
    const beadStates = tmpl.beads
      .map((id) => {
        const catalogBead = getCatalogBead(id)!;
        return catalogBeadToBeadState(catalogBead);
      });

    const designCode = encodeDesign(beadStates);

    await prisma.template.create({
      data: {
        name: tmpl.name,
        designCode,
        beadCount: tmpl.beads.length,
      },
    });

    console.log(`  ✓ ${tmpl.name} (${tmpl.beads.length} beads)`);
  }

  const count = await prisma.template.count();
  console.log(`\nDone! ${count} templates seeded.`);
}

main()
  .catch((e) => {
    console.error("Seed failed:", e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

"use client";

import { useState } from "react";
import dynamic from "next/dynamic";
import { useDesignStore } from "@/stores/useDesignStore";
import { EditorToolbar } from "./EditorToolbar";
import { BeadCatalogPanel } from "./BeadCatalogPanel";

// Dynamically import Scene to avoid SSR issues with Three.js / WebGL
const Scene = dynamic(() => import("@/components/scene/Scene"), {
  ssr: false,
});

/**
 * Main editor layout: full-viewport 3D canvas with bottom toolbar and
 * slide-up catalog bottom sheet.
 *
 * EditorCanvas is the Zustand subscriber that bridges store ↔ scene.
 * The Scene component stays "dumb" — it receives beads as a prop.
 */
export default function EditorCanvas() {
  const [catalogOpen, setCatalogOpen] = useState(false);

  // Subscribe to design store
  const beads = useDesignStore((s) => s.beads);
  const selectedBeadId = useDesignStore((s) => s.selectedBeadId);

  return (
    <div className="relative w-screen h-screen flex flex-col overflow-hidden">
      {/* ── 3D Canvas Area ────────────────────────────────────────── */}
      {/* touch-action: none on canvas-container prevents browser
          scroll/zoom gestures on touch devices */}
      <div className="canvas-container flex-1 w-full relative">
        <Scene beads={beads} selectedBeadId={selectedBeadId} />
      </div>

      {/* ── Catalog Bottom Sheet ─────────────────────────────────── */}
      <BeadCatalogPanel
        isOpen={catalogOpen}
        onClose={() => setCatalogOpen(false)}
      />

      {/* ── Bottom Toolbar ───────────────────────────────────────── */}
      <EditorToolbar
        catalogOpen={catalogOpen}
        onToggleCatalog={() => setCatalogOpen((prev) => !prev)}
      />
    </div>
  );
}

import { defineConfig } from "prisma/config";
import "dotenv/config";

export default defineConfig({
  schema: "prisma/schema.prisma",
  datasource: {
    url: process.env.DATABASE_URL!,
  },
  migrations: {
    path: "prisma/migrations",
    seed: "tsx prisma/seed.ts",
  },
});

"use client";

import { useEffect } from "react";
import { useDesignStore } from "@/stores/useDesignStore";
import EditorCanvas from "@/components/editor/EditorCanvas";

/**
 * Blank editor page for "Начать с нуля" (start from scratch).
 *
 * Clears the store on mount to ensure no leftover beads from a previous
 * session leak through, then renders the EditorCanvas.
 */
export default function EditorPage() {
  useEffect(() => {
    useDesignStore.getState().clearDesign();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return <EditorCanvas />;
}
